func (s *Store) SaveBookmark(ctx context.Context, b Bookmark) error {
	return s.db.QueryRow(ctx, INSERT INTO bookmarks (url, title, tags) VALUES ($1,$2,$3) RETURNING id, b.URL, b.Title, b.Tags).Scan(&b.ID)
}

func (l *Limiter) Allow(key string) bool {
	now := time.Now().UnixNano()
	l.trim(key, now)
	return l.count(key) < l.max
}
